Bash(.venv/bin/python - <<'EOF'
import yaml, sys, json
sys.path.insert\(0, "."\)
from pipeline.clients.token_manager import TokenManager
from pipeline.clients.central_client import CentralClient

with open\("config/credentials.yaml"\) as f:
    creds = yaml.safe_load\(f\)

src = creds["source_account"]
tm = TokenManager\(client_id=src["client_id"], client_secret=src["client_secret"], cache_key="source"\)
client = CentralClient\(base_url=src["base_url"], token_manager=tm\)

_GLOBAL_SCOPE_ID = "79236221864456192"
_SWITCHES_SCOPE_ID = "79244358948933632"

def _skip\(exc\):
    t = \(getattr\(getattr\(exc, "response", None\), "text", ""\) or ""\).lower\(\)
    return "duplicate" in t or "already exists" in t

def scope_map\(scope_id, persona, resource\):
    try:
        client.post\("/network-config/v1/scope-maps", data={
            "scope-map": [{
                "scope-name": scope_id,
                "scope-id": int\(scope_id\),
                "persona": persona,
                "resource": resource,
            }]
        }\)
        print\(f"  scope-map {persona} → {resource} @ {scope_id}: OK"\)
    except Exception as e:
        t = \(getattr\(getattr\(e, "response", None\), "text", ""\) or ""\).lower\(\)
        if "duplicate" in t or "already exists" in t:
            print\(f"  scope-map {persona} → {resource} @ {scope_id}: already exists"\)
        else:
            print\(f"  scope-map {persona} → {resource} @ {scope_id}: FAILED — {e}"\)

# ── Step 1: Create allow-all policy ──────────────────────────────────────────
POLICY_NAME = "sys_policy_pap_normalDevice"
policy_body = {
    "name": POLICY_NAME,
    "type": "LOCAL",
    "rules": [
        {"sequence": 10, "class": "sys_pap_normalDevice_ip_allow_1",  "class-type": "ipv4", "action": "permit"},
        {"sequence": 20, "class": "sys_pap_normalDevice_ipv6_allow_1","class-type": "ipv6", "action": "permit"},
    ]
}
try:
    r = client.post\(f"/network-config/v1/policies/{POLICY_NAME}", data=policy_body\)
    print\(f"Policy '{POLICY_NAME}': created — {r}"\)
except Exception as e:
    if _skip\(e\):
        print\(f"Policy '{POLICY_NAME}': already exists"\)
    else:
        print\(f"Policy '{POLICY_NAME}': FAILED — {e}"\)
        resp_text = getattr\(getattr\(e, "response", None\), "text", ""\)
        print\(f"  response: {resp_text}"\)

# Scope-map policy
for sid in \(_GLOBAL_SCOPE_ID, _SWITCHES_SCOPE_ID\):
    scope_map\(sid, "ACCESS_SWITCH", f"policies/{POLICY_NAME}"\)

# ── Step 2: Create role ───────────────────────────────────────────────────────
ROLE_NAME = "normalDevice"
role_body = {
    "name": ROLE_NAME,
    "description": "Normal device — access VLAN 200, allow all",
    "vlan-parameters": {"wired-access-vlan-id": 200},
    "session-parameters": {
        "auth-mode": "DEVICE_MODE",
        "stp-admin-edge-port": True,
        "poe-priority": "LOW",
        "tunneled-node-server-redirect": False,
    },
    "policy": POLICY_NAME,
}
try:
    r = client.post\(f"/network-config/v1/roles/{ROLE_NAME}", data=role_body\)
    print\(f"\\nRole '{ROLE_NAME}': created — {r}"\)
except Exception as e:
    if _skip\(e\):
        try:
            client.put\(f"/network-config/v1/roles/{ROLE_NAME}", data=role_body\)
            print\(f"\\nRole '{ROLE_NAME}': updated existing"\)
        except Exception as e2:
            print\(f"\\nRole '{ROLE_NAME}': update failed — {e2}"\)
    else:
        print\(f"\\nRole '{ROLE_NAME}': FAILED — {e}"\)
        resp_text = getattr\(getattr\(e, "response", None\), "text", ""\)
        print\(f"  response: {resp_text}"\)

# Scope-map role
for sid in \(_GLOBAL_SCOPE_ID, _SWITCHES_SCOPE_ID\):
    scope_map\(sid, "ACCESS_SWITCH", f"roles/{ROLE_NAME}"\)

# ── Step 3: Create port profile ───────────────────────────────────────────────
PP_NAME = "normal-device-access"
pp_desc_body = {"description": "Normal device — access VLAN 200, allow all"}
pp_body = {
    "mode": "AUTO",
    "enable": True,
    "routing": False,
    "dpi-enable": True,
    "lldp": {"mode": "TX_RX"},
    "switchport": {"interface-mode": "ACCESS", "access-vlan": 200},
    "stp": {
        "enable": True,
        "admin-edge-port": True,
        "bpdu-guard": True,
        "bpdu-filter": False,
        "loop-guard": False,
        "root-guard": False,
        "rpvst-filter": False,
        "rpvst-guard": False,
        "tcn-guard": False,
        "priority": 6,
    },
    "poe": {"enabled": True, "allocation-method": "USAGE", "priority": "LOW"},
}
try:
    client.post\(f"/network-config/v1/sw-port-profiles/{PP_NAME}", data=pp_desc_body\)
    client.put\(f"/network-config/v1/sw-port-profiles/{PP_NAME}", data=pp_body\)
    print\(f"\\nPort profile '{PP_NAME}': created"\)
except Exception as e:
    if _skip\(e\):
        try:
            client.put\(f"/network-config/v1/sw-port-profiles/{PP_NAME}", data=pp_body\)
            print\(f"\\nPort profile '{PP_NAME}': updated existing"\)
        except Exception as e2:
            print\(f"\\nPort profile '{PP_NAME}': update failed — {e2}"\)
    else:
        print\(f"\\nPort profile '{PP_NAME}': FAILED — {e}"\)
        resp_text = getattr\(getattr\(e, "response", None\), "text", ""\)
        print\(f"  response: {resp_text}"\)

# Scope-map port profile
for sid in \(_GLOBAL_SCOPE_ID, _SWITCHES_SCOPE_ID\):
    scope_map\(sid, "ACCESS_SWITCH", f"sw-port-profiles/{PP_NAME}"\)

print\("\\nDone."\)
EOF)
